async function startRazorpayCheckout(button) {
    if (button?.disabled) return;
    const buttons = Array.from(document.querySelectorAll("#modal-payment .pay-btn"));
    const originalLabels = new Map(buttons.map((btn) => [btn, btn.innerHTML]));
    showPaymentError("");

    buttons.forEach((btn) => {
        btn.disabled = true;
        btn.classList.add("is-loading");
    });
    if (button) button.innerHTML = `<span>Opening secure checkout...</span><i class="fa-solid fa-circle-notch fa-spin"></i>`;

    try {
        if (typeof window.Razorpay !== "function") {
            throw new Error("Razorpay checkout script did not load. Please refresh and try again.");
        }

        const config = await getAppRuntimeConfig();
        const payment = config.payment || DEFAULT_AUDIT_PAYMENT;
        const razorpayKeyId = config.razorpayKeyId || window.APP_CONFIG?.razorpayKeyId;
        if (!razorpayKeyId) {
            throw new Error("Razorpay key is missing from QA/frontend configuration.");
        }

        const orderResponse = await fetch(getApiUrl("/api/create-order"), {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                amount: payment.amount,
                currency: payment.currency,
                receipt: currentAuditTrackId || `audit_${Date.now()}`,
            }),
        });
        const order = await orderResponse.json().catch(() => ({}));
        if (!orderResponse.ok) {
            throw new Error(order?.error || "Could not create payment order.");
        }

        const verifiedPayment = await new Promise((resolve, reject) => {
            let completed = false;
            let dismissed = false;
            const checkout = new window.Razorpay({
                key: razorpayKeyId,
                amount: order.amount,
                currency: order.currency,
                name: "AsliProperty",
                description: "Full Digital Property Audit",
                order_id: order.order_id,
                prefill: {
                    name: userData.name || "",
                    email: userData.email || "",
                    contact: String(userData.phone || "").replace(/\D/g, ""),
                },
                notes: {
                    trackId: currentAuditTrackId || "",
                    locality: userData.locality || "",
                    budget: userData.budget || "",
                },
                theme: { color: "#141E3A" },
                modal: {
                    ondismiss: async () => {
                        if (!completed && !dismissed) {
                            dismissed = true;
                            showPaymentError("Confirming payment status...");
                            try {
                                const recoveredPayment = await recoverCapturedRazorpayPayment(order, payment);
                                if (recoveredPayment) {
                                    completed = true;
                                    resolve(recoveredPayment);
                                    return;
                                }
                                reject(new Error("Payment cancelled. You can try again when ready."));
                            } catch (error) {
                                reject(error);
                            }
                        }
                    },
                },
                handler: async (response) => {
                    if (completed) return;
                    completed = true;
                    try {
                        const verifyResponse = await fetch(getApiUrl("/api/verify-payment"), {
                            method: "POST",
                            headers: { "Content-Type": "application/json" },
                            body: JSON.stringify({
                                razorpay_payment_id: response.razorpay_payment_id,
                                razorpay_order_id: response.razorpay_order_id,
                                razorpay_signature: response.razorpay_signature,
                            }),
                        });
                        const verify = await verifyResponse.json().catch(() => ({}));
                        if (!verifyResponse.ok) {
                            throw new Error(verify?.error || "Payment verification failed.");
                        }
                        resolve({
                            ...verify,
                            razorpay_payment_id: response.razorpay_payment_id,
                            razorpay_order_id: response.razorpay_order_id,
                            amount: order.amount,
                            currency: order.currency,
                            receipt: order.receipt || "",
                        });
                    } catch (error) {
                        try {
                            const recoveredPayment = await recoverCapturedRazorpayPayment(order, payment);
                            if (recoveredPayment) {
                                resolve(recoveredPayment);
                                return;
                            }
                        } catch {}
                        completed = false;
                        reject(error);
                    }
                },
            });

            checkout.on("payment.failed", (response) => {
                const description = response?.error?.description || "Payment failed. Please try another method.";
                showPaymentError(description);
            });
            checkout.open();
        });

        currentPaymentDetails = {
            status: "paid",
            provider: "razorpay",
            paymentId: verifiedPayment.razorpay_payment_id || verifiedPayment.payment_id || "",
            orderId: verifiedPayment.razorpay_order_id || verifiedPayment.order_id || "",
            amount: Number(verifiedPayment.amount || payment.amount),
            currency: verifiedPayment.currency || payment.currency || "INR",
            receipt: verifiedPayment.receipt || currentAuditTrackId || "",
            verifiedAt: new Date().toISOString(),
        };
        showModalStage("details");
    } catch (error) {
        console.error(error);
        showPaymentError(error?.message || "Payment could not be completed. Please try again.");
    } finally {
        buttons.forEach((btn) => {
            btn.disabled = false;
            btn.classList.remove("is-loading");
            btn.innerHTML = originalLabels.get(btn) || btn.innerHTML;
        });
    }
}

function processPayment() {
    startRazorpayCheckout();
}

function getFirestore() {
    initFirebaseIfNeeded();
    if (typeof window.firebase?.firestore !== "function") {
        throw new Error("Firestore SDK not loaded. Add firebase-firestore-compat.js to the page.");
    }
    return window.firebase.firestore();
}

async function uploadAuditDocuments(trackId) {
    if (!selectedAuditFiles.length) return [];

    try {
        return await Promise.all(
            selectedAuditFiles.map(async (file, index) => {
                const response = await fetch(getApiUrl(`/api/upload-document/${encodeURIComponent(trackId)}?i=${index + 1}`), {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/octet-stream",
                        "x-file-name": encodeURIComponent(file.name || `Document ${index + 1}`),
                        "x-file-type": file.type || "application/octet-stream",
                    },
                    body: file,
                });

                const data = await response.json().catch(() => ({}));
                if (!response.ok) {
                    throw new Error(data?.error || `Document upload failed (HTTP ${response.status}).`);
                }
                return data;
            })
        );
    } catch (error) {
        throw new Error(error?.message || "Document upload failed. Please try again.");
    }
}

async function saveAuditOrderToFirestore(trackId, property, notes, documents) {
    const db = getFirestore();
    const FieldValue = window.firebase.firestore.FieldValue;
    const paymentDetails = currentPaymentDetails || null;

    const payload = {
        trackId,
        createdAt: FieldValue.serverTimestamp(),
        status: "New Lead",
        paymentStatus: paymentDetails?.status || "pending",
        payment: paymentDetails
            ? {
                ...paymentDetails,
                verifiedAt: FieldValue.serverTimestamp(),
            }
            : null,
        user: { ...userData },
        property: {
            rera: property?.rera || "",
            survey: property?.survey || "",
            village: property?.village || "",
            mandal: property?.mandal || "",
        },
        notes: notes || "",
        documents: documents || [],
        client: {
            userAgent: navigator.userAgent,
            locale: navigator.language,
        },
    };

    console.log("[auditOrders] saving", trackId, payload);
    await db.collection("auditOrders").doc(trackId).set(payload, { merge: true });
    console.log("[auditOrders] saved", trackId);
}

async function submitAudit() {
    const survey = document.getElementById("propSurvey").value.trim();
    if (!survey) { alert("Survey Number is required for verification"); return; }

    const btn = document.querySelector("#modal-details button");
    if (btn?.disabled) return;
    const original = btn?.innerHTML;
    if (btn) {
        btn.innerHTML = `<i class="fa-solid fa-circle-notch fa-spin"></i> Submitting...`;
        btn.disabled = true;
    }

    const trackId = currentAuditTrackId || "PV-" + Math.floor(1000 + Math.random() * 9000);
    const property = {
        rera: document.getElementById("propRera").value.trim(),
        survey,
        village: document.getElementById("propVillage").value.trim(),
        mandal: document.getElementById("propMandal").value.trim(),
    };
    const notes = document.getElementById("propNotes")?.value.trim() || "";

    try {
        const documents = await uploadAuditDocuments(trackId);
        await saveAuditOrderToFirestore(trackId, property, notes, documents);
        document.getElementById("finalTrackId").innerText = trackId;
        showModalStage("success");
    } catch (e) {
        console.error(e);
        alert(e?.message || "Failed to submit order. Please try again.");
    } finally {
        if (btn) {
            btn.innerHTML = original;
            btn.disabled = false;
        }
    }
}

function renderSelectedFiles() {
    const fileList = document.getElementById("fileList");
    const dropzoneInner = document.getElementById("dropzone-inner");
    if (!fileList) return;

    fileList.innerHTML = selectedAuditFiles
        .map((file, index) => {
            const sizeMb = file.size ? `${(file.size / (1024 * 1024)).toFixed(2)} MB` : "";
            return `
                <li class="file-item">
                    <i class="fa-solid fa-file-lines file-icon"></i>
                    <span class="file-name">${escapeHtml(file.name || `Document ${index + 1}`)}</span>
                    <span class="file-size">${escapeHtml(sizeMb)}</span>
                    <button class="file-remove" type="button" onclick="event.stopPropagation(); removeSelectedFile(${index})" aria-label="Remove file">&times;</button>
                </li>
            `;
        })
        .join("");

    if (dropzoneInner) {
        dropzoneInner.classList.toggle("hidden", selectedAuditFiles.length > 0);
    }
}

function removeSelectedFile(index) {
    selectedAuditFiles.splice(index, 1);
    renderSelectedFiles();
}

function handleFileSelect(files) {
    const incoming = Array.from(files || []);
    const maxBytes = 10 * 1024 * 1024;
    const accepted = [];
    const rejected = [];

    incoming.forEach((file) => {
        if (file.size > maxBytes) {
            rejected.push(file.name || "Unnamed file");
        } else {
            accepted.push(file);
        }
    });

    selectedAuditFiles = [...selectedAuditFiles, ...accepted];
    renderSelectedFiles();

    if (rejected.length) {
        alert(`These files are above 10MB and were not added: ${rejected.join(", ")}`);
    }
}

function wireDocumentUpload() {
    const dropzone = document.getElementById("dropzone");
    const input = document.getElementById("propFiles");
    if (!dropzone || !input) return;

    ["dragenter", "dragover"].forEach((eventName) => {
        dropzone.addEventListener(eventName, (event) => {
            event.preventDefault();
            event.stopPropagation();
            dropzone.classList.add("dropzone-over");
        });
    });

    ["dragleave", "drop"].forEach((eventName) => {
        dropzone.addEventListener(eventName, (event) => {
            event.preventDefault();
            event.stopPropagation();
            dropzone.classList.remove("dropzone-over");
        });
    });

    dropzone.addEventListener("drop", (event) => {
        handleFileSelect(event.dataTransfer?.files);
        input.value = "";
    });

    input.addEventListener("change", () => {
        handleFileSelect(input.files);
        input.value = "";
    });
}

